import { Component, inject, OnInit, OnDestroy, ChangeDetectorRef, NgZone } from '@angular/core';
import { RouterModule } from '@angular/router'; 
import { CommonModule } from '@angular/common';
import { NotificationCenterComponent } from '../../../shared/components/notification-center/notification-center.component';
import { NotificationService } from '../../../core/services/notification.service';
import { Subscription } from 'rxjs';

@Component({
  selector: 'app-candidate-layout',
  standalone: true,
  imports: [RouterModule, CommonModule, NotificationCenterComponent], 
  templateUrl: './candidate-layout.component.html',
  styleUrls: ['./candidate-layout.component.css']
})
export class CandidateLayoutComponent implements OnInit, OnDestroy {
  private notificationService = inject(NotificationService);
  private cdr = inject(ChangeDetectorRef);
  private zone = inject(NgZone);

  candidateName = 'Candidat';
  
  // 🚀 Variable réactive liée au *ngIf du HTML pour afficher la popup
  selectedNotifData: any = null; 
  private notifSub: Subscription | null = null;

  ngOnInit() {
    const storedName = localStorage.getItem('name');
    if (storedName) {
      this.candidateName = storedName;
    }

    // 🚀 INTERCEPTION DU SIGNAL : Écoute le clic sur la cloche du candidat
    this.notifSub = this.notificationService.openApplication$.subscribe(data => {
      if (!data) {
        this.zone.run(() => {
          this.selectedNotifData = null;
          this.cdr.detectChanges();
        });
        return;
      }

      console.log("📥 Layout Candidat - Données relationnelles reçues de MySQL :", data);
      
      // Force l'affichage dans la zone Angular pour éviter les blocages de rafraîchissement
      this.zone.run(() => {
        this.selectedNotifData = data;
        this.cdr.detectChanges(); // Réveille l'interface pour faire jaillir la popup !
      });
    });
  }

  // ❌ Méthode de fermeture liée au bouton "Fermer" et à la croix (X)
  closeModal() {
    this.zone.run(() => {
      this.selectedNotifData = null;
      this.notificationService.clearTrigger(); // Vide la mémoire du service partagé
      this.cdr.detectChanges();
    });
  }

  ngOnDestroy() {
    // Désinscription impérative pour éviter les écoutes fantômes en mémoire
    if (this.notifSub) {
      this.notifSub.unsubscribe();
    }
    this.notificationService.clearTrigger();
  }

  onLogout() {
    localStorage.clear();
    window.location.href = '/login';
  }
}
<div class="candidate-app-container">
  
  <!-- 🧭 SIDEBAR COMPLÈTE & PROFESSIONNELLE DU CANDIDAT (D'origine, inchangée) -->
  <aside class="candidate-sidebar">
    <div class="sidebar-brand">
      <div class="logo-icon"><i class="bi bi-rocket-takeoff-fill"></i></div>
      <div class="logo-text">Tun<span>Job</span> Candidate</div>
    </div>

    <!-- Menu de navigation -->
    <nav class="sidebar-nav">
      <div class="nav-section-title">Recherche & Suivi</div>
      
      <!-- Lien 1 : Recherche d'emploi -->
      <a routerLink="/candidate/job-search" routerLinkActive="active" class="nav-link-item">
        <i class="bi bi-search"></i> Trouver un emploi
      </a>
      
      <!-- Lien 2 : Historique des candidatures -->
      <a routerLink="/candidate/applications-list" routerLinkActive="active" class="nav-link-item">
        <i class="bi bi-file-earmark-check-fill"></i> Mes candidatures
      </a>

      <div class="nav-section-title">Mon Profil & CV</div>
      
      <!-- Lien 3 : Générateur de CV -->
      <a routerLink="/candidate/cv-builder" routerLinkActive="active" class="nav-link-item">
        <i class="bi bi-file-earmark-person-fill"></i> Construire mon CV
      </a>
      
      <!-- Lien 4 : Visualiser le CV public -->
      <a routerLink="/candidate/cv-view" routerLinkActive="active" class="nav-link-item">
        <i class="bi bi-eye-fill"></i> Voir mon CV public
      </a>

      <!-- Lien 5 : Configuration du Profil Personnel -->
      <a routerLink="/candidate/profile-settings" routerLinkActive="active" class="nav-link-item">
        <i class="bi bi-sliders"></i> Configuration Profil
      </a>

      <!-- Bouton Déconnexion sécurisé en bas de la Sidebar -->
      <a (click)="onLogout()" class="nav-link-item logout-item" style="margin-top: auto; color: #ef4444; cursor: pointer;">
        <i class="bi bi-box-arrow-left" style="color: #ef4444;"></i> Quitter la session
      </a>
    </nav>
  </aside>

  <!-- 💻 ZONE DE CONTENU PRINCIPALE (DROITE) (D'origine, inchangée) -->
  <main class="candidate-main">
    <header class="candidate-header" style="display: flex; justify-content: space-between; align-items: center; background-color: #ffffff; padding: 24px 40px; border-bottom: 1px solid #e2e8f0;">
      <div class="header-welcome">
        <h2>Bienvenue, <span style="color: #0ea5e9;">{{ candidateName }}</span> 👋</h2>
        <p>Propulsez votre carrière et trouvez les meilleures opportunités en Tunisie.</p>
      </div>

      <!-- INJECTION UNIQUE DU CENTRE DE NOTIFICATIONS SANS INTERFÉRER SUR LES AUTRES MODALS -->
      <div style="display: flex; align-items: center; gap: 20px;">
        <app-notification-center></app-notification-center>
      </div>
    </header>

    <!-- ZONE D'INJECTION DYNAMIQUE POUR LES SOUS-PAGES CANDIDAT (D'origine, inchangée) -->
    <div class="candidate-content-body" style="padding: 30px 40px;">
      <router-outlet></router-outlet>
    </div>
  </main>

  <!-- 🎛️ UNIQUE AJOUT : MODAL DU SUIVI DE STATUT (S'affiche uniquement au clic sur une notif) -->
    <!-- 🎛️ POPUP DE SUIVI DE CANDIDATURE CANDIDAT EN SURIMPRESSION (DESIGN RECRUTEUR ALIGNÉ) -->
  <div *ngIf="selectedNotifData" class="global-popup-backdrop" (click)="closeModal()">
    <div class="global-popup-card" (click)="$event.stopPropagation()">
        
        <!-- En-tête -->
        <div class="modal-header">
          <h3>Détails de l'entreprise & Statut</h3>
          <button class="close-btn" (click)="closeModal()">&times;</button>
        </div>

        <!-- Corps des détails avec intégration du logo de la société -->
        <div class="modal-body">
          
          <!-- Conteneur Flex pour aligner la photo à gauche et les infos à droite -->
          <div style="display: flex; gap: 24px; align-items: flex-start; margin-bottom: 20px;">
            
            <!-- 📸 Bloc Photo (Logo de l'entreprise) -->
            <div style="flex-shrink: 0; display: flex; flex-direction: column; align-items: center; gap: 10px; width: 110px;">
              <div style="width: 85px; height: 85px; border-radius: 50%; border: 1px solid #cbd5e1; overflow: hidden; background: #ffffff; display: flex; align-items: center; justify-content: center;">
                <img [src]="selectedNotifData.avatar_logo ? 'http://localhost:3000/logos/' + selectedNotifData.avatar_logo : 'assets/images/default-company.png'" 
                     (error)="$any($event.target).src='assets/images/default-company.png'"
                     alt="Logo entreprise" 
                     style="width: 100%; height: 100%; object-fit: cover;">
              </div>
              <span style="font-size: 11px; font-weight: 700; color: #64748b; text-transform: uppercase;">Société</span>
            </div>

            <!-- Bloc des informations textuelles de la Société -->
            <div style="flex-grow: 1; display: flex; flex-direction: column; gap: 12px;">
              <div class="info-row" style="display: flex;">
                <span class="info-label" style="width: 150px; flex-shrink: 0;">Entreprise :</span> 
                <strong class="info-value text-slate" style="color: #0ea5e9;">{{ selectedNotifData.company_name }}</strong>
              </div>
              <div class="info-row" style="display: flex;">
                <span class="info-label" style="width: 150px; flex-shrink: 0;">Poste ciblé :</span> 
                <strong class="info-value text-slate">{{ selectedNotifData.job_title }}</strong>
              </div>
              <div class="info-row" style="display: flex;">
                <span class="info-label" style="width: 150px; flex-shrink: 0;">Adresse e-mail :</span> 
                <span class="info-value">{{ selectedNotifData.email }}</span>
              </div>
              <div class="info-row" style="display: flex;">
                <span class="info-label" style="width: 150px; flex-shrink: 0;">Numéro de téléphone :</span> 
                <span class="info-value">{{ selectedNotifData.phone || 'Non renseigné' }}</span>
              </div>
              <div class="info-row" style="display: flex;">
                <span class="info-label" style="width: 150px; flex-shrink: 0;">Ville / Région :</span> 
                <span class="info-value">{{ selectedNotifData.address || 'Non spécifiée' }}</span>
              </div>
            </div>

          </div>
          
          <!-- Boîte du message de statut -->
          <div class="summary-box" style="margin-top: 15px; padding: 16px; background: #f8fafc; border-radius: 8px; border-left: 4px solid #0ea5e9;">
            <span class="summary-title" style="color: #0f172a; font-weight: 700; font-size: 13px; display: block; margin-bottom: 8px;">
              Statut actuel de votre dossier
            </span>
            <div style="display: flex; align-items: center; gap: 10px; margin-bottom: 10px;">
              <span style="font-size: 13px; color: #64748b;">État :</span>
              <span style="display: inline-block; padding: 4px 14px; border-radius: 20px; font-size: 12px; font-weight: 700; background: #e0f2fe; color: #0369a1;">
                {{ selectedNotifData.status }}
              </span>
            </div>
            <p class="summary-text" style="margin: 0; color: #475569; font-size: 13px; line-height: 1.6;">
              {{ selectedNotifData.message }}
            </p>
          </div>
        </div>

        <!-- Pied de page -->
        <div class="modal-footer" style="display: flex; justify-content: flex-end; padding-top: 16px; border-top: 1px solid #f1f5f9;">
          <button class="btn-secondary" (click)="closeModal()" style="padding: 8px 24px !important; font-size: 12px !important; font-weight: 600 !important; cursor: pointer !important;">
            Fermer
          </button>
        </div>

    </div>
  </div>


</div>
